var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하아……. 하아…….","JPN":"はあ……はあ……","ENG":"Huff... Huff...","TWN":"呼……呼……"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"후우. 성가신 놈이었네.","JPN":"ふう。やっかいな相手だったわ。","ENG":"Whew. That was tough.","TWN":"呼～那傢伙真不好對付！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"잘했어. 그래도 둘이라서 좀 더 쉽게 해치웠네.","JPN":"よくやったわ。二人で対処できたおかげで、思ってたより簡単に倒せたわね。","ENG":"Good job. Two heads are better than one, right?","TWN":"幹得好！二對一還是比較省力點。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……내 의뢰는 망하고 말이야.","JPN":"……俺の依頼は失敗になったけどな。","ENG":"And there goes my payment.","TWN":"……我的委託完蛋了。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"뭐가 걱정이야. 사지 멀쩡한 젊은 녀석이.","JPN":"心配ないわ。元気だし、若いし、まだ稼げるチャンスはあるわよ。","ENG":"Don't worry. You're young and strong.","TWN":"擔心什麼，你好手好腳的，還怕賺不到錢嗎？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"네가 헴스워스 영감 성질머리를 몰라서 그래.","JPN":"あんたはヘムズワース爺の性格を知らないからそう言えるんだ。","ENG":"You don't know Helmsworth.","TWN":"你不知道漢姆沃斯的個性啦！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이번에도 외상 못 갚으면 새로 커스텀한 총의 실험체가 될 거라고.","JPN":"今回も返済できなかったら、新作のカスタムガンの実験体にされちまう。","ENG":"If I don't pay my tab this time, he'll test his new custom guns on me.","TWN":"這次再不還錢的話，我會成為他的槍下魂啦！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"저런, 안 본 사이 엄살이 늘었네.","JPN":"あらら、見ないうちに臆病になっちゃったのね。","ENG":"Oh, you've become a coward in the short time I was away.","TWN":"哇，才一陣子不見，講話變這麼浮誇！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"뭐야? 벌써 괴도가 나타난 거야?!","JPN":"なんだ？　もう怪盗が現れたのか！？","ENG":"What? Was the Thief already here?","TWN":"什麼嘛～怪盜已經出現過啦？！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"설마 혼자 잡은 건 아니겠지?","JPN":"まさか一人で捕まえたんじゃないよな？","ENG":"You didn't catch him by yourself, did you?","TWN":"你該不會自己都處理完了吧？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"우리도 한 몫 한 걸로 쳐줘야 한다?","JPN":"もちろん、俺らも一緒に捕まえたことにしてくれるよな？","ENG":"Because we did our bit, you know.","TWN":"我們要假裝也有參一腳嗎？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……어디 갔나 했더니 이제야 왔군.","JPN":"……どこへ消えたのかと思っていたら、ようやく来たな。","ENG":"Finally, you're back.","TWN":"……我還想說你們人咧？結果都處理完才出現。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"……어라?","JPN":"……あれ？","ENG":"Err?","TWN":"……哦？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"혹시…… 이 괴물이 괴도 르블랑인가?","JPN":"もしかして……この化け物が怪盗ルブランか？","ENG":"Wait... Is this monster LeBlanc the Thief?","TWN":"這個怪物……就是怪盜布勒朗？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"크흠, 흠. 확실히 그림자도 보기 싫어지는 생김새긴 한데.","JPN":"ふむ、ふむ。確かに影も見たくない顔立ちではあるな。","ENG":"Kahem, kahem. I definitely wouldn't have wanted to see it or its shadow.","TWN":"咳咳，長得確實不太想看到他的人影。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"이런. 내 샷건, <color=#ffd34c>그란투리스모</color>와 맞붙기엔 너무 연약했나 보군.","JPN":"やれやれ。俺のショットガン<color=#ffd34c>グランドツアー</color>と戦うには弱すぎたようだな。","ENG":"Too bad It must have been too weak to face my shotgun, <color=#ffd34c>Gran Turismo</color>.","TWN":"我看這傢伙似乎不是我的霰彈槍 <color=#ffd34c>格蘭多·里斯莫</color>的對手！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……그럴 리가 있겠냐.","JPN":"……そんなわけないだろ。","ENG":"Well, that's ridiculous.","TWN":"……沒這種事啦！"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};